import{c as e,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"SafeHarness: Lifecycle-Integrated Security Architecture for LLM-based Agent Deployment","description":"","frontmatter":{"title":"SafeHarness: Lifecycle-Integrated Security Architecture for LLM-based Agent Deployment","arxiv_id":"2604.13630","authors":"Xixun Lin, Yang Liu, Yancheng Chen, Yongxuan Wu, Yucheng Ning, Yilong Liu, Nan Sun, Shun Zhang, Bin Chong, Chuan Zhou, Yanan Cao","fetched":"2026-05-23","published":"2026-04-13","source":"https://arxiv.org/abs/2604.13630","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-13-safeharness-lifecycle-security-2604-13630.md","filePath":"research/agent-harness/references/2026-04-13-safeharness-lifecycle-security-2604-13630.md","lastUpdated":1779920788000}'),n={name:"research/agent-harness/references/2026-04-13-safeharness-lifecycle-security-2604-13630.md"};function o(s,t,d,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="safeharness-lifecycle-integrated-security-architecture-for-llm-based-agent-deployment" tabindex="-1">SafeHarness: Lifecycle-Integrated Security Architecture for LLM-based Agent Deployment <a class="header-anchor" href="#safeharness-lifecycle-integrated-security-architecture-for-llm-based-agent-deployment" aria-label="Permalink to &quot;SafeHarness: Lifecycle-Integrated Security Architecture for LLM-based Agent Deployment&quot;">​</a></h1><p><strong>Authors</strong>: Xixun Lin, Yang Liu, Yancheng Chen, Yongxuan Wu, Yucheng Ning, Yilong Liu, Nan Sun, Shun Zhang, Bin Chong, Chuan Zhou, Yanan Cao<br><strong>Affiliations</strong>: Institute of Information Engineering (Chinese Academy of Sciences), Academy of Mathematics and Systems Science (Chinese Academy of Sciences), Institute of Applied Physics and Computational Mathematics, Peking University<br><strong>Published</strong>: April 2026<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2604.13630" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.13630</a><br><strong>arXiv ID</strong>: 2604.13630<br><strong>Categories</strong>: cs.CR, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>SafeHarness presents a security framework embedding defense mechanisms throughout the agent harness lifecycle. The system achieves <strong>approximately 38% reduction in Unsafe Behavior Rate (UBR) and 42% reduction in Attack Success Rate (ASR)</strong> compared to unprotected baselines while maintaining core task utility across three harness configurations and multiple attack scenarios. The key insight: security must be an architectural principle embedded in harness design, not an external layer added on top.</p><hr><h2 id="_1-problem-structural-gaps-in-existing-agent-security" tabindex="-1">1. Problem: Structural Gaps in Existing Agent Security <a class="header-anchor" href="#_1-problem-structural-gaps-in-existing-agent-security" aria-label="Permalink to &quot;1. Problem: Structural Gaps in Existing Agent Security&quot;">​</a></h2><p>The authors identify three structural gaps in existing agent security approaches:</p><table tabindex="0"><thead><tr><th>Gap</th><th>Description</th></tr></thead><tbody><tr><td><strong>Context Blindness</strong></td><td>External defenses lack visibility into harness-internal state and adversarial provenance</td></tr><tr><td><strong>Inter-layer Isolation</strong></td><td>Security mechanisms operate independently without coordinated response</td></tr><tr><td><strong>Lack of Resilience</strong></td><td>Defenses employ binary pass-or-block decisions without progressive degradation</td></tr></tbody></table><p>These gaps mean existing defenses (system-prompt warnings, guardrails, LlamaFirewall) fail against sophisticated, multi-vector attacks that exploit harness-internal execution paths.</p><hr><h2 id="_2-four-layer-architecture" tabindex="-1">2. Four-Layer Architecture <a class="header-anchor" href="#_2-four-layer-architecture" aria-label="Permalink to &quot;2. Four-Layer Architecture&quot;">​</a></h2><p>SafeHarness implements defense across four lifecycle phases:</p><h3 id="layer-1-inform-input-processing" tabindex="-1">Layer 1: Inform (Input Processing) <a class="header-anchor" href="#layer-1-inform-input-processing" aria-label="Permalink to &quot;Layer 1: Inform (Input Processing)&quot;">​</a></h3><p><strong>Stage</strong>: Before any model processing</p><p><strong>Mechanisms</strong>:</p><ul><li><strong>Structural sanitization</strong>: Unicode/encoding obfuscation removal</li><li><strong>Pattern-based detection</strong>: Regex matching for known injection phrases</li><li><strong>Semantic filtering</strong>: LLM judge for paraphrased injections that evade pattern matching</li><li><strong>Provenance tagging</strong>: Every input tagged with source type and trust level</li></ul><p>Filters both user inputs AND tool outputs (addressing indirect prompt injection via poisoned tool responses).</p><h3 id="layer-2-verify-decision-making" tabindex="-1">Layer 2: Verify (Decision Making) <a class="header-anchor" href="#layer-2-verify-decision-making" aria-label="Permalink to &quot;Layer 2: Verify (Decision Making)&quot;">​</a></h3><p><strong>Stage</strong>: Before executing model-generated actions</p><p><strong>Three-tiered progressive verification</strong>:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Method</th><th>Cost</th><th>Depth</th></tr></thead><tbody><tr><td>Tier 1</td><td>Rule-based compliance, deterministic risk scoring</td><td>Low</td><td>Shallow</td></tr><tr><td>Tier 2</td><td>Contextual judge model evaluation</td><td>Medium</td><td>Medium</td></tr><tr><td>Tier 3</td><td>Causal diagnostics: does action stem from legitimate intent or adversarial injection?</td><td>High</td><td>Deep</td></tr></tbody></table><p>Tier escalation occurs automatically based on risk score from Tier 1.</p><h3 id="layer-3-constrain-action-execution" tabindex="-1">Layer 3: Constrain (Action Execution) <a class="header-anchor" href="#layer-3-constrain-action-execution" aria-label="Permalink to &quot;Layer 3: Constrain (Action Execution)&quot;">​</a></h3><p><strong>Stage</strong>: During tool execution</p><p><strong>Mechanisms</strong>:</p><ul><li><strong>Capability tokens</strong>: Per-tool tokens with TTL and invocation limits</li><li><strong>Tier enforcement</strong>: Dynamic privilege ceilings preventing privilege escalation</li><li><strong>Integrity verification</strong>: HMAC-SHA256 signatures on tool descriptions (detecting tool tampering)</li></ul><p><strong>Five tool risk tiers</strong>: <code>read_only</code> → <code>write</code> → <code>execute</code> → <code>network</code> → <code>destructive</code></p><h3 id="layer-4-correct-state-update" tabindex="-1">Layer 4: Correct (State Update) <a class="header-anchor" href="#layer-4-correct-state-update" aria-label="Permalink to &quot;Layer 4: Correct (State Update)&quot;">​</a></h3><p><strong>Stage</strong>: After execution, state recovery</p><p><strong>Mechanisms</strong>:</p><ul><li><strong>State checkpointing</strong>: Periodic snapshots including protected memory</li><li><strong>Attack-triggered rollback</strong>: Revert to safe checkpoint upon confirmed attack</li><li><strong>Adaptive degradation</strong>: 5 degradation levels progressively restricting tool access</li><li><strong>Automatic recovery</strong>: Restore privileges after configurable safe-action window</li></ul><hr><h2 id="_3-cross-layer-mechanisms" tabindex="-1">3. Cross-Layer Mechanisms <a class="header-anchor" href="#_3-cross-layer-mechanisms" aria-label="Permalink to &quot;3. Cross-Layer Mechanisms&quot;">​</a></h2><h3 id="protected-memory-with-provenance" tabindex="-1">Protected Memory with Provenance <a class="header-anchor" href="#protected-memory-with-provenance" aria-label="Permalink to &quot;Protected Memory with Provenance&quot;">​</a></h3><p>Append-only store tracking: source, authorship, timestamp, content hash. Detects anomalous mutation patterns that indicate memory injection attacks.</p><h3 id="entropy-monitor" tabindex="-1">Entropy Monitor <a class="header-anchor" href="#entropy-monitor" aria-label="Permalink to &quot;Entropy Monitor&quot;">​</a></h3><p>Tracks violation rate within sliding window (default: 20 actions). Escalates Layer 2 verification when windowed violation rate exceeds threshold (default: 0.3). This enables <strong>proactive defense</strong> rather than reactive blocking.</p><h3 id="inter-layer-feedback-channels" tabindex="-1">Inter-Layer Feedback Channels <a class="header-anchor" href="#inter-layer-feedback-channels" aria-label="Permalink to &quot;Inter-Layer Feedback Channels&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source Layer</th><th>Target Layer</th><th>Trigger</th><th>Action</th></tr></thead><tbody><tr><td>L1</td><td>L2</td><td>Injection detection</td><td>Escalate verification tier</td></tr><tr><td>L2</td><td>L4</td><td>Confirmed attack</td><td>Trigger rollback/degradation</td></tr><tr><td>L4</td><td>L3</td><td>Degradation activated</td><td>Tighten privilege ceiling</td></tr><tr><td>L4</td><td>L2/L3</td><td>Recovery window elapsed</td><td>Restore normal operation</td></tr></tbody></table><hr><h2 id="_4-threat-model" tabindex="-1">4. Threat Model <a class="header-anchor" href="#_4-threat-model" aria-label="Permalink to &quot;4. Threat Model&quot;">​</a></h2><p>Six attack vectors mapped to execution phases:</p><table tabindex="0"><thead><tr><th>Threat</th><th>Phase</th><th>Primary Defense Layer</th></tr></thead><tbody><tr><td>Direct Injection</td><td>Input</td><td>L1 (Inform)</td></tr><tr><td>Indirect Injection (tool output poisoning)</td><td>Input</td><td>L1 (Inform)</td></tr><tr><td>Tool Abuse</td><td>Execution</td><td>L3 (Constrain)</td></tr><tr><td>Tool Tampering (description modification)</td><td>Execution</td><td>L3 HMAC verification</td></tr><tr><td>Memory Corruption (fabricated history)</td><td>Cross-phase</td><td>Protected Memory</td></tr><tr><td>Privilege Escalation (parameter escalation)</td><td>Execution</td><td>L3 (Constrain)</td></tr></tbody></table><p>Attack scenarios tested:</p><ul><li><strong>A1</strong>: Context poisoning</li><li><strong>A2</strong>: Indirect injection (tool output poisoning)</li><li><strong>A3</strong>: Tool tampering (description modification, parameter escalation)</li><li><strong>A4</strong>: Memory injection (fabricated history)</li><li><strong>A5</strong>: Composite (simultaneous multi-vector attacks)</li></ul><hr><h2 id="_5-experimental-results" tabindex="-1">5. Experimental Results <a class="header-anchor" href="#_5-experimental-results" aria-label="Permalink to &quot;5. Experimental Results&quot;">​</a></h2><h3 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h3><ul><li><strong>Dataset</strong>: Agent-SafetyBench (2,000 tasks, 349 environments, 8 risk categories)</li><li><strong>Agent Models</strong>: DeepSeek-V3.2 (Chat and Reasoner modes)</li><li><strong>Judge Model</strong>: GPT-4o-mini (separate from agent model)</li><li><strong>Harness Configurations</strong>: ReAct, Multi-Agent, Self-Evolving</li><li><strong>Baselines</strong>: Unprotected, System-Prompt, Guardrail, LlamaFirewall, SafeHarness</li></ul><h3 id="safety-results-unsafe-behavior-rate-—-lower-is-better" tabindex="-1">Safety Results (Unsafe Behavior Rate — lower is better) <a class="header-anchor" href="#safety-results-unsafe-behavior-rate-—-lower-is-better" aria-label="Permalink to &quot;Safety Results (Unsafe Behavior Rate — lower is better)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Unprotected UBR</th><th>SafeHarness UBR</th><th>Reduction</th></tr></thead><tbody><tr><td>ReAct (Chat)</td><td>51.18%</td><td>28.74%</td><td><strong>-22.4pp</strong></td></tr><tr><td>Multi-Agent (Chat)</td><td>44.99%</td><td>26.31%</td><td><strong>-18.7pp</strong></td></tr><tr><td>Self-Evolving (Chat)</td><td>61.98%</td><td>39.18%</td><td><strong>-22.8pp</strong></td></tr><tr><td><strong>Average</strong></td><td>—</td><td>—</td><td><strong>~38%</strong></td></tr></tbody></table><h3 id="attack-success-rate-reduction" tabindex="-1">Attack Success Rate Reduction <a class="header-anchor" href="#attack-success-rate-reduction" aria-label="Permalink to &quot;Attack Success Rate Reduction&quot;">​</a></h3><p>22.8–24.7 percentage points across configurations.</p><h3 id="utility-preservation-task-completion-rate" tabindex="-1">Utility Preservation (Task Completion Rate) <a class="header-anchor" href="#utility-preservation-task-completion-rate" aria-label="Permalink to &quot;Utility Preservation (Task Completion Rate)&quot;">​</a></h3><ul><li><strong>ReAct / Self-Evolving</strong>: TCR within 1–2pp of unprotected — utility maintained</li><li><strong>Multi-Agent</strong>: 86.5% → 77.9% TCR — reflects blocked unsafe completions (expected tradeoff)</li></ul><h3 id="utility-under-attack-ua-completed-and-safe" tabindex="-1">Utility Under Attack (UA = completed AND safe) <a class="header-anchor" href="#utility-under-attack-ua-completed-and-safe" aria-label="Permalink to &quot;Utility Under Attack (UA = completed AND safe)&quot;">​</a></h3><ul><li><strong>ReAct (Chat)</strong>: 45.6% → 67.5% (+21.9pp) — substantial improvement in safe completions</li></ul><h3 id="defense-activity" tabindex="-1">Defense Activity <a class="header-anchor" href="#defense-activity" aria-label="Permalink to &quot;Defense Activity&quot;">​</a></h3><ul><li>Guardrail/LlamaFirewall: 54–184 blocked actions per evaluation</li><li>SafeHarness: <strong>709–1,477 blocked actions</strong> — reflecting multi-layer per-step checking</li></ul><hr><h2 id="_6-comparison-to-baselines" tabindex="-1">6. Comparison to Baselines <a class="header-anchor" href="#_6-comparison-to-baselines" aria-label="Permalink to &quot;6. Comparison to Baselines&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Defense</th><th>Architecture</th><th>Harness Visibility</th><th>Multi-Layer Coordination</th></tr></thead><tbody><tr><td>System-Prompt</td><td>Static text</td><td>None</td><td>No</td></tr><tr><td>Guardrail</td><td>Output filter</td><td>Output only</td><td>No</td></tr><tr><td>LlamaFirewall</td><td>Input/output filter</td><td>Minimal</td><td>No</td></tr><tr><td><strong>SafeHarness</strong></td><td>Lifecycle integration</td><td>Full (4 layers)</td><td>Yes</td></tr></tbody></table><hr><h2 id="_7-evaluation-metrics" tabindex="-1">7. Evaluation Metrics <a class="header-anchor" href="#_7-evaluation-metrics" aria-label="Permalink to &quot;7. Evaluation Metrics&quot;">​</a></h2><p><strong>Safety</strong>: UBR (Unsafe Behavior Rate), ASR (Attack Success Rate), NNH (Expected interactions before unsafe outcome = 1/UBR)</p><p><strong>Utility</strong>: TCR (Task Completion Rate), UA (Utility Under Attack = completed AND safe)</p><p><strong>Defense Activity</strong>: Blk (total intercepted actions)</p><hr><h2 id="_8-limitations" tabindex="-1">8. Limitations <a class="header-anchor" href="#_8-limitations" aria-label="Permalink to &quot;8. Limitations&quot;">​</a></h2><ul><li>Tool execution environment is simulated, not deployed on real backends</li><li>Evaluation uses LLM-as-Judge with potential bias (mitigated by separate agent/judge models)</li><li>Multi-tier verification introduces inference overhead (concentrated on suspicious actions via entropy monitor)</li><li>Attack coverage reflects documented threat vectors, not comprehensive adversarial landscape</li></ul><hr><h2 id="_9-implications-for-harness-design" tabindex="-1">9. Implications for Harness Design <a class="header-anchor" href="#_9-implications-for-harness-design" aria-label="Permalink to &quot;9. Implications for Harness Design&quot;">​</a></h2><ol><li><p><strong>Security as architecture</strong>: External bolt-on security fails because it lacks harness-internal visibility. Security must be built into the harness lifecycle from the start.</p></li><li><p><strong>Provenance tracking</strong>: Every input&#39;s source must be tracked. Unsigned tool outputs are an attack surface.</p></li><li><p><strong>Progressive degradation over binary blocking</strong>: Binary block/allow creates brittleness. 5-level degradation maintains partial functionality under attack.</p></li><li><p><strong>Multi-layer coordination</strong>: Individual security layers are insufficient. Cross-layer feedback (entropy monitor, escalation channels) is essential for detecting sophisticated attacks.</p></li><li><p><strong>HMAC for tool integrity</strong>: Tool descriptions are a high-value attack target. Signing them with HMAC-SHA256 provides tamper detection.</p></li></ol><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Lin et al. (2026) SafeHarness: Lifecycle-Integrated Security Architecture for LLM-based Agent Deployment. arXiv:2604.13630</li><li>Greshake et al. (2023) Not what you&#39;ve signed up for: Compromising real-world LLM-integrated applications with indirect prompt injection</li><li>Liu et al. (2024) Agent-SafetyBench: Evaluating the Safety of LLM Agents</li><li>Inan et al. (2023) Llama Guard: LLM-based input-output safeguard for human-AI conversations</li><li>Anthropic (2025) Claude&#39;s Constitution and safety principles</li><li>Perez and Ribeiro (2022) Ignore previous prompt: Attack techniques for language models</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper Concept</th><th>cc-workspace Current State</th><th>Opportunity</th></tr></thead><tbody><tr><td>Provenance tagging</td><td>No source tracking on tool outputs</td><td>Tag external content in <code>&lt;untrusted_external_data&gt;</code> (already in subagent-strategy.md) ✅</td></tr><tr><td>HMAC tool integrity</td><td>No tool description signing</td><td>Low priority for local harness</td></tr><tr><td>Entropy monitor (violation rate)</td><td>Manual observation only</td><td>Add violation counter to GOTCHAS.md tracking</td></tr><tr><td>Progressive degradation (5 levels)</td><td>Binary: proceed or stop</td><td>Model as: normal → warn → require confirmation → read-only → halt</td></tr><tr><td>Protected memory with provenance</td><td>MEMORY.md (no provenance)</td><td>Add source/date fields to MEMORY.md entries</td></tr><tr><td>Indirect injection defense (L1)</td><td><code>&lt;untrusted_external_data&gt;</code> wrapping</td><td>✅ Already partially aligned—strengthen in hooks</td></tr><tr><td>UBR metric</td><td>No safety metric tracking</td><td>Consider tracking unexpected tool calls per session</td></tr></tbody></table>',80)])])}const p=e(n,[["render",o]]);export{g as __pageData,p as default};
